import React, { useState } from 'react';

const FIELDS = [
  { key: 'name', label: 'Name', type: 'text' },
  { key: 'email', label: 'Email', type: 'email' },
  { key: 'password', label: 'Password', type: 'password' },
];

function validate(v) {
  const e = {};
  if (!v.name.trim()) e.name = 'Name is required';
  if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(v.email)) e.email = 'Enter a valid email';
  if (v.password.length < 8) e.password = 'At least 8 characters';
  return e;
}

export default function ValidatedForm() {
  const [values, setValues] = useState({ name: '', email: '', password: '' });
  const [touched, setTouched] = useState({});
  const [submitted, setSubmitted] = useState(false);
  const [done, setDone] = useState(false);

  const errors = validate(values);
  const isValid = Object.keys(errors).length === 0;

  const onSubmit = (e) => {
    e.preventDefault();
    setSubmitted(true);
    if (isValid) setDone(true);
  };

  if (done) {
    return <p style={{ color: '#16a34a', fontWeight: 600 }}>✓ Submitted as {values.name} ({values.email})</p>;
  }

  return (
    <form onSubmit={onSubmit} style={{ maxWidth: 320, display: 'flex', flexDirection: 'column', gap: 14 }} noValidate>
      {FIELDS.map((f) => {
        const show = (touched[f.key] || submitted) && errors[f.key];
        return (
          <label key={f.key} style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {f.label}
            <input
              type={f.type}
              value={values[f.key]}
              onChange={(e) => setValues((v) => ({ ...v, [f.key]: e.target.value }))}
              onBlur={() => setTouched((t) => ({ ...t, [f.key]: true }))}
              style={{ padding: 8, border: `1px solid ${show ? '#dc2626' : '#cbd5e1'}`, borderRadius: 6 }}
            />
            {show && <small style={{ color: '#dc2626' }}>{errors[f.key]}</small>}
          </label>
        );
      })}
      <button
        type="submit"
        disabled={submitted && !isValid}
        style={{ padding: '10px', cursor: 'pointer', background: '#2563eb', color: '#fff', border: 'none', borderRadius: 6 }}
      >
        Sign up
      </button>
    </form>
  );
}

