import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Field { key: string; label: string; type: string; }

@Component({
  selector: 'app-validated-form',
  template: `
    <p *ngIf="done" style="color: #16a34a; font-weight: 600;">✓ Submitted as {{ values['name'] }} ({{ values['email'] }})</p>
    <form *ngIf="!done" (submit)="$event.preventDefault(); onSubmit()" novalidate style="max-width: 320px; display: flex; flex-direction: column; gap: 14px;">
      <label *ngFor="let f of fields" style="display: flex; flex-direction: column; gap: 4px;">
        {{ f.label }}
        <input
          [type]="f.type"
          [value]="values[f.key]"
          (input)="values[f.key] = $any($event.target).value"
          (blur)="touched[f.key] = true"
          [style.border]="'1px solid ' + (showError(f.key) ? '#dc2626' : '#cbd5e1')"
          style="padding: 8px; border-radius: 6px;"
        />
        <small *ngIf="showError(f.key)" style="color: #dc2626;">{{ errors[f.key] }}</small>
      </label>
      <button type="submit" [disabled]="submitted && !isValid" style="padding: 10px; cursor: pointer; background: #2563eb; color: #fff; border: none; border-radius: 6px;">Sign up</button>
    </form>
  `,
})
export class ValidatedFormComponent {
  fields: Field[] = [
    { key: 'name', label: 'Name', type: 'text' },
    { key: 'email', label: 'Email', type: 'email' },
    { key: 'password', label: 'Password', type: 'password' },
  ];
  values: Record<string, string> = { name: '', email: '', password: '' };
  touched: Record<string, boolean> = {};
  submitted = false;
  done = false;

  get errors(): Record<string, string> {
    const e: Record<string, string> = {};
    if (!this.values['name'].trim()) {
      e['name'] = 'Name is required';
    }
    if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(this.values['email'])) {
      e['email'] = 'Enter a valid email';
    }
    if (this.values['password'].length < 8) {
      e['password'] = 'At least 8 characters';
    }
    return e;
  }

  get isValid(): boolean {
    return Object.keys(this.errors).length === 0;
  }

  showError(key: string): boolean {
    return (this.touched[key] || this.submitted) && !!this.errors[key];
  }

  onSubmit(): void {
    this.submitted = true;
    if (this.isValid) {
      this.done = true;
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Form Validation Demo</h1>
      <app-validated-form></app-validated-form>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, ValidatedFormComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
